const visitorKeys = {
  Program: ["body"],
};

export default {
  name: "svelte-eslint-parser",
  VisitorKeys: visitorKeys,
  parseForESLint(code, options = {}) {
    return {
      ast: {
        type: "Program",
        sourceType: "module",
        body: [],
        range: [0, code.length],
        loc: {
          start: { line: 1, column: 0 },
          end: { line: 1, column: code.length },
        },
        comments: [],
        tokens: [],
      },
      visitorKeys,
      services: {
        visitorFlag: options.eslintVisitorKeys === true,
        scopeFlag: options.eslintScopeManager === true,
        filePath: typeof options.filePath === "string" && options.filePath.endsWith("App.svelte"),
      },
    };
  },
};
